import subprocessimport sys# List of packages requiredrequired_packages = ['roboflow', 'opencv-python', 'numpy', 'pandas','PIL','math','os','matplotlib.pyplot','io','torch']# Install missing packagesfor package in required_packages:    try:        __import__(package)    except ImportError:        subprocess.check_call([sys.executable, "-m", "pip", "install", package])import roboflowimport cv2import numpy as npimport pandas as pdfrom PIL import Imageimport mathimport osimport matplotlib.pyplot as plt import torchimport io roboflow.login()rf = roboflow.Roboflow()cropping_method="no"def fig2img(fig):     buf = io.BytesIO()     fig.savefig(buf)     buf.seek(0)     img = Image.open(buf)     return img #############################################################def get_average_rgb_in_circle(image, center, radius):    # Create a mask image with white circle    mask = np.zeros(image.shape[:2], dtype=np.uint8)    cv2.circle(mask, center, radius, 255, -1)    # Extract pixels within the circle using the mask    masked_image = cv2.bitwise_and(image, image, mask=mask)    # Calculate the average RGB value within the circle    average_color = cv2.mean(masked_image, mask=mask)[:3]        return average_color    # Load the image#############################################################def normalize_brightness(image, target_brightness=128):    # Convert image to grayscale to calculate current brightness    gray = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)    current_brightness = np.mean(gray)        # Calculate scaling factor    scale = target_brightness / current_brightness if current_brightness > 0 else 1        # Normalize brightness    normalized_image = cv2.convertScaleAbs(image, alpha=scale, beta=0)    return normalized_imagecurrent_dir = os.getcwd()key_path = os.path.join(current_dir, "key.csv")# Read CSV fileskey = pd.read_csv(key_path)key=key.astype(str)key=key.replace('nan',np.nan)params = key.iloc[:, 3].dropna().str.strip()clear=os.listdir("./input")for file in clear:    os.remove("./input/"+file)inputs=os.listdir("./converted")inputs = [f for f in inputs if f.lower().endswith((".jpg", ".tif"))]inputs=[item for item in inputs if not any(char in item for char in ["runs"])]if cropping_method=="no":######NO CROP###############    for i in inputs:        filename=i[:-4]        file=Image.open('./converted/'+i)        filename=filename.replace(" ","")        filename=filename.replace(".tif","")        file.convert('RGB').save("./input/"+filename+".jpg",format="JPEG")        #################################################################################################PART  2 - adjustclear=os.listdir("./temp")for file in clear:    os.remove("./temp/"+file)    pt1=os.listdir("./input")  contrast=float(params[0])brightness=float(params[1])for img in pt1:    im=cv2.imread('./input/'+img)    im=normalize_brightness(im,target_brightness=100)    im=cv2.addWeighted(im,contrast,np.zeros(im.shape,im.dtype),0,brightness)    filename = img.split(".jpg")[0]    cv2.imwrite('./temp/'+filename+".jpg",im)#not_yolo#clean output folderclear=os.listdir("./runs/detect/annotations")for file in clear:    os.remove("./runs/detect/annotations/"+file)if os.path.exists("./runs/detect/predict")==True:    clear=os.listdir("./runs/detect/predict")    for file in clear:        os.remove("./runs/detect/predict/"+file)    os.rmdir("./runs/detect/predict")files=os.listdir("./temp")from ultralytics import YOLOmodel=YOLO("./model_weights/"+params[4]+".pt")for file in files:        results=model.predict("./temp/"+file,conf=float(params[2]),iou=float(params[3]))    # Extract bounding boxes, classes, names, and confidences    boxes = results[0].boxes.xyxy.tolist()    classes = results[0].boxes.cls.tolist()    names = results[0].names    confidences = results[0].boxes.conf.tolist()    # Iterate through the results    for box, cls, conf in zip(boxes, classes, confidences):        x1, y1, x2, y2 = box        confidence = conf        detected_class = cls        name = names[int(cls)]          coords=pd.DataFrame(boxes,confidences)    coords.insert(0,"classes",classes)            coords.to_csv('./runs/detect/annotations/'+file+'.csv')#clean temp folderclear=os.listdir("./runs/detect/for_merging")for file in clear:    os.remove("./runs/detect/for_merging/"+file)    clear=os.listdir("./runs/detect/check")for file in clear:    os.remove("./runs/detect/check/"+file)    #check if all circles are OKpath="./temp/"annot="./runs/detect/annotations"data2=[]inputs=os.listdir("./input")inputs=[file.removesuffix('.jpg') for file in inputs]for e,i in enumerate(os.listdir(annot)):    if e < 1000000000:        filename = i.split(".jpg")[0]+".jpg"        img = cv2.imread(os.path.join(path,filename))        df = pd.read_csv(os.path.join(annot,i))                for row in df.iterrows():            x1 = int(row[1][2])            x2=int(row[1][4])            y1 = int(row[1][3])            y2 = int(row[1][5])            classs=int(row[1][1])            if classs==1: #alive                cv2.rectangle(img,(x1,y1),(x2,y2),(255,0,0), 2)            elif classs==2: #dead                cv2.rectangle(img,(x1,y1),(x2,y2),(0,0,255), 2)            elif classs==0: #???                cv2.rectangle(img,(x1,y1),(x2,y2),(0,255,0), 2)            else: #debri                cv2.rectangle(img,(x1,y1),(x2,y2),(255,255,0), 2)            x=int((x1+x2)/2)            y=int((y1+y2)/2)            img = cv2.putText(                img=img,                text="conf:"+str(round(row[1][0],2)),                org=(x,y),                fontFace = cv2.FONT_HERSHEY_DUPLEX,                fontScale = 0.8,                color = (0, 0, 0),                thickness = 3                 )            img = cv2.putText(                img=img,                text="conf:"+str(round(row[1][0],2)),                org=(x,y),                fontFace = cv2.FONT_HERSHEY_DUPLEX,                fontScale = 0.8,                color = (125, 246, 55),                thickness = 2                 )        img = cv2.putText(                img=img,                text="no. of alive:"+str(len(df[df["classes"]==0])),                org=(50,50),                fontFace = cv2.FONT_HERSHEY_DUPLEX,                fontScale = 1,                color = (0, 0, 0),                thickness = 3                 )        img = cv2.putText(            img=img,            text="no. of alive:"+str(len(df[df["classes"]==0])),            org=(50,50),            fontFace = cv2.FONT_HERSHEY_DUPLEX,            fontScale = 1,            color = (255, 255, 255),            thickness = 2             )        img = cv2.putText(                img=img,                text="no. of dead:"+str(len(df[df["classes"]==1])),                org=(50,100),                fontFace = cv2.FONT_HERSHEY_DUPLEX,                fontScale = 1,                color = (0, 0, 0),                thickness = 3                 )                img = cv2.putText(            img=img,            text="no. of dead:"+str(len(df[df["classes"]==1])),            org=(50,100),            fontFace = cv2.FONT_HERSHEY_DUPLEX,            fontScale = 1,            color = (255, 255, 255),            thickness = 2             )        img = cv2.putText(            img=img,            text="no. of ????:"+str(len(df[df["classes"]==2])),            org=(50,150),            fontFace = cv2.FONT_HERSHEY_DUPLEX,            fontScale = 1,            color = (0, 0, 0),            thickness = 3             )                img = cv2.putText(            img=img,            text="no. of ????:"+str(len(df[df["classes"]==2])),            org=(50,150),            fontFace = cv2.FONT_HERSHEY_DUPLEX,            fontScale = 1,            color = (255, 255, 255),            thickness = 2             )        cv2.imwrite("./runs/detect/for_merging/"+filename,img)                #get number of dead and alive in csv        alive=len(df[df["classes"]==0])        dead=len(df[df["classes"]==1])        unsure=len(df[df["classes"]==2])        well=str(i.split(".jpg")[0])        data=[well,alive,dead,unsure]                    data2.append(data)                    final=pd.DataFrame(data2)final.to_csv("deadoralive_counts.csv",index=False)                            #recombine merged images and add clean imageinputs=os.listdir("./input")inputs=[file.removesuffix('.jpg') for file in inputs]splitted=os.listdir("./runs/detect/for_merging")splitted=[file.removesuffix('.jpg') for file in splitted]for im in inputs:        full=cv2.imread("./input/"+im+".jpg")        img=cv2.imread("./runs/detect/for_merging/"+im+".jpg")        check=np.hstack((img,full))        cv2.imwrite("./runs/detect/check/"+im+".jpg",check)# Define pathscounts_path = os.path.join(current_dir, "deadoralive_counts.csv")counts = pd.read_csv(counts_path)# Extract groupsgroup1 = key.iloc[:, 0].dropna().str.strip()group2 = key.iloc[:, 1].dropna().str.strip()group3 = key.iloc[:, 2].dropna().str.strip()# Initialize empty dataframefull = pd.DataFrame()# Nested loops over group2, group3, and group1for g2 in group2:    count_g2 = counts[counts.iloc[:, 0].str.contains(g2, na=False, regex=True)]    for g3 in group3:        row = {"g2": g2, "g3": g3}        count_g3 = count_g2[count_g2.iloc[:, 0].str.contains(g3, na=False, regex=True)]        for g1 in group1:            count_g1 = count_g3[count_g3.iloc[:, 0].str.contains(g1, na=False, regex=True)]            alive = count_g1.iloc[:, 1].sum()            total = count_g1.iloc[:, 2].sum()+alive            survival = alive / total if total > 0 else 0            row[g1] = survival                # Append row to full dataframe        full = pd.concat([full, pd.DataFrame([row])], ignore_index=True)# Set row names and column names (like in R)full.index = [f"{row['g3']}_{row['g2']}" for _, row in full.iterrows()]full.columns = ["g2", "g3"] + group1.tolist()# Save the resultoutput_path = os.path.join(current_dir, "deadoralive_counts_summary.csv")full.to_csv(output_path, index=False)